  "options": [
    {
      "text": "API Gateway"
    },
    {
      "text": "EKS",
      "hint": "EKS आपके स्वयं के लंबी अवधि के वेबसॉकेट सेवाओं को चला सकता है।"
    },
    {
      "text": "Lightsail",
      "hint": "Lightsail इंस्टैंस आपके स्वयं के वेबसॉकेट सर्वर को चला सकते हैं।"
    },
    {
      "text": "AppSync",
      "hint": "AppSync वेबसॉकेट्स पर प्रबंधित रियल-टाइम ग्राफ़क्यूएल सब्सक्रिप्शन प्रदान करता है, लेकिन अनियमित रूप से रॉ सॉकेट्स नहीं।"
    },
    {
      "text": "EC2",
      "hint": "EC2 आपके स्वयं के लंबी अवधि के वेबसॉकेट सर्वर प्रक्रिया को चला सकता है।"
    }
  ],
  "questionProse": [
    "👋 आशा है आपको अब तक मज़ा आ रहा है!\n\n      अब एक कठिन सवाल है...\n\n      कौन सी AWS सेवा प्रबंधित वेबसॉकेट एपीआई प्रदान करती है जहाँ AWS क्लाइंट कनेक्शन का स्वामित्व करता है और संगति में संदेशों को रूट करता है?"
  ],
  "explanationProse": [
    "API Gateway द्विदिशा वेबसॉकेट एपीआई का समर्थन करता है, लेकिन कार्यरति API Gateway द्वारा प्रबंधित होती है और आपके सर्वर प्रक्रिया में एक सीधा सॉकेट नहीं होता है।\n      API Gateway क्लाइंट कनेक्शन को बनाए रखता है और संदेशों को Lambda, HTTP एंडपॉइंट या अन्य संगतियों को रूट करता है। संदेशों को API Gateway Management API के माध्यम से जुड़े क्लाइंट में वापस भेजा जा सकता है।\n\n      अन्य विकल्प बहुत अधिक वेबसॉकेट-अनुकूल हैं:\n      - Lightsail: सरल वेबसॉकेट सेटअप के लिए बेहतरीन 👌\n      - AppSync: प्रबंधित ग्राफ़क्यूएल सब्सक्रिप्शन के लिए वेबसॉकेट्स का उपयोग करता है\n      - EC2: वेबसॉकेट्स के लिए आपका प्राचीन \"कुछ भी करें\" विकल्प\n      - EKS: पैमाने पर वेबसॉकट क्लस्टर चलाने के लिए उत्तम\n\n      प्रो टिप: अगर आपको रॉ वेबसॉकेट शक्ति की आवश्यकता है, तो कंप्यूट विकल्पों पर जाएं!"
  ]
}
